mapper.select:
SELECT ln.*, tb.textbook_name AS textbookName, tc.catalog_name AS catalogName FROM learning_notes ln LEFT JOIN textbook tb ON ln.textbook_id = tb.id LEFT JOIN textbook_catalog tc ON ln.catalogue_id = tc.id
AND tb.textbook_name LIKE CONCAT('%', #{param.textbookName}, '%')
AND tc.catalog_name LIKE CONCAT('%', #{param.catalogName}, '%')
AND ln.add_datetime >= #{param.startTime}
AND ln.add_datetime <= #{param.endTime}
AND ln.creator = #{id}
ORDER BY ln.add_datetime
ASC
DESC

SELECT ln.*, tb.textbook_name AS textbookName, tc.catalog_name AS catalogName, (SELECT COUNT(*) FROM learning_notes ln_count WHERE ln_count.textbook_id = ln.textbook_id AND ln_count.creator = #{id}) AS noteCount FROM ( -- 获取每个教材最新的一条笔记（按添加时间倒序） SELECT ln2.* FROM learning_notes ln2 WHERE ln2.creator = #{id} AND ln2.id IN ( SELECT MAX(ln3.id) FROM learning_notes ln3 WHERE ln3.creator = #{id}
AND EXISTS ( SELECT 1 FROM textbook tb_filter WHERE tb_filter.id = ln3.textbook_id AND tb_filter.textbook_name LIKE CONCAT('%', #{param.textbookName}, '%') )
GROUP BY ln3.textbook_id ) ) ln LEFT JOIN textbook tb ON ln.textbook_id = tb.id LEFT JOIN textbook_catalog tc ON ln.catalogue_id = tc.id
AND tc.catalog_name LIKE CONCAT('%', #{param.catalogName}, '%')
AND ln.add_datetime >= #{param.startTime}
AND ln.add_datetime <= #{param.endTime}
ORDER BY ln.add_datetime
ASC
DESC
